def assess(record: dict) -> str:
    required_fields = {"case_id", "seed", "params", "metric", "rerun_metric", "tolerance"}
    absent = sorted(required_fields - set(record))
    if absent:
        return "MISSING:" + ",".join(absent)
    ok = not (abs(record["metric"] - record["rerun_metric"]) > record["tolerance"])
    return "PASS" if ok else "MARK_RUN_NONREPRODUCIBLE"

valid = {"case_id": "CASO-TAC-047-1A", **{"seed": 42, "params": {"depth": 4}, "metric": 0.81, "rerun_metric": 0.805, "tolerance": 0.01}}
invalid = {"case_id": "CASO-TAC-047-1A", **{"seed": 42, "params": {"depth": 4}, "metric": 0.0, "rerun_metric": 0.805, "tolerance": 0.01}}
incomplete = dict(valid)
if "tolerance" in incomplete:
    del incomplete["tolerance"]
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)

